// State-specific explanations for Q1–Q10
// Format: STATE_EXPL[stateName][questionNum] = [null, germanText, englishText]
const STATE_EXPL = {
  "Baden-Württemberg": {
    1: [null, "Das Wappen zeigt den goldenen Hirsch des Hauses Württemberg und die rot-weißen Schrägbalken Badens. Schwarz und Gold sind die Farben des Landes.", "The coat of arms shows the golden stag of Württemberg and the red-white diagonal bars of Baden. Black and gold are the state's colours."],
    2: [null, "Der Neckar-Odenwald-Kreis liegt im Norden Baden-Württembergs, zwischen dem Neckartal und dem Odenwald. Er gehört zur Metropolregion Rhein-Neckar.", "The Neckar-Odenwald district is in northern Baden-Württemberg, between the Neckar valley and the Odenwald forest. It belongs to the Rhine-Neckar metropolitan region."],
    3: [null, "Der Landtag in Baden-Württemberg wird alle 5 Jahre gewählt. Die meisten deutschen Bundesländer haben ebenfalls 5-jährige Wahlperioden.", "The state parliament in Baden-Württemberg is elected every 5 years. Most German states also have 5-year electoral terms."],
    4: [null, "In Baden-Württemberg dürfen Jugendliche ab 16 Jahren bei Kommunalwahlen wählen. BW gehörte zu den ersten Ländern, die das Wahlalter für Kommunalwahlen gesenkt haben.", "In Baden-Württemberg, young people aged 16 and over may vote in local elections. BW was among the first states to lower the voting age for local elections."],
    5: [null, "Die Landesflagge Baden-Württembergs ist schwarz-gold. Schwarz und Gold stehen für das Herzogtum Württemberg; die Farben erinnern an den goldenen Hirsch im Wappen.", "Baden-Württemberg's state flag is black and gold. Black and gold represent the Duchy of Württemberg; the colours echo the golden stag in the coat of arms."],
    6: [null, "Die Landeszentrale für politische Bildung (LpB) bietet kostenlose Materialien, Veranstaltungen und Onlineangebote zu politischen Themen. Jedes Bundesland hat eine eigene LpB.", "The State Centre for Civic Education (LpB) offers free materials, events and online resources on political topics. Every German state has its own LpB."],
    7: [null, "Stuttgart ist die Landeshauptstadt und eines der wichtigsten Industriezentren Deutschlands. Hier haben Daimler, Porsche und Bosch ihren Hauptsitz.", "Stuttgart is the state capital and one of Germany's most important industrial centres. Daimler, Porsche and Bosch are headquartered here."],
    8: [null, "Baden-Württemberg liegt im Südwesten Deutschlands und grenzt an Frankreich und die Schweiz. Es ist das drittgrößte Bundesland nach Fläche.", "Baden-Württemberg is in south-west Germany, bordering France and Switzerland. It is the third-largest state by area."],
    9: [null, "In den 13 deutschen Flächenländern heißt der Regierungschef Ministerpräsident/in. In den drei Stadtstaaten (Berlin, Hamburg, Bremen) gibt es andere Amtsbezeichnungen.", "In Germany's 13 non-city states, the head of government is called Ministerpräsident/in. The three city-states (Berlin, Hamburg, Bremen) use different titles."],
    10: [null, "Baden-Württemberg hat keinen Außenminister, weil Außenpolitik ausschließlich Sache des Bundes ist. Nur der Bundesaußenminister vertritt Deutschland international.", "Baden-Württemberg has no foreign minister because foreign policy is exclusively a federal matter. Only the Federal Foreign Minister represents Germany internationally."]
  },
  "Bayern": {
    1: [null, "Das bayerische Wappen zeigt die blau-weißen Rauten (Wecken) der Grafen von Bogen sowie den Frankenrechen und den Panther. Die Farben Weiß und Blau prägen Bayern seit dem Mittelalter.", "The Bavarian coat of arms shows the blue-white lozenges of the Counts of Bogen, the Franconian rake, and the panther. White and blue have characterised Bavaria since the Middle Ages."],
    2: [null, "Altötting ist ein Landkreis im Südosten Bayerns, bekannt als bedeutendster Marienwallfahrtsort Deutschlands. Das Gnadenbild der Schwarzen Madonna ist seit Jahrhunderten ein Pilgerziel.", "Altötting is a district in south-eastern Bavaria, known as Germany's most important Marian pilgrimage site. The image of the Black Madonna has been a pilgrimage destination for centuries."],
    3: [null, "Der bayerische Landtag wird alle 5 Jahre gewählt. Bayern hat seit 1946 eine stabile parlamentarische Tradition mit fünfjährigen Wahlperioden.", "The Bavarian state parliament is elected every 5 years. Bavaria has had a stable parliamentary tradition with five-year terms since 1946."],
    4: [null, "In Bayern liegt das Mindestalter für Kommunalwahlen bei 18 Jahren. Damit gehört Bayern zu den wenigen Bundesländern, die das Wahlalter noch nicht auf 16 gesenkt haben.", "In Bavaria the minimum voting age for local elections is 18. Bavaria is one of the few states that has not yet lowered the voting age to 16."],
    5: [null, "Die Landesflagge Bayerns ist weiß-blau. Die Farben stammen aus dem Mittelalter und gehen auf die Grafen von Bogen zurück, die ihr Territorium an die Wittelsbacher vererbten.", "Bavaria's state flag is white and blue. The colours date from the Middle Ages and trace back to the Counts of Bogen, who passed their territory to the Wittelsbachs."],
    6: [null, "Die Bayerische Landeszentrale für politische Bildungsarbeit (BLZ) informiert Bürgerinnen und Bürger über politische und gesellschaftliche Themen mit Publikationen, Filmen und Ausstellungen.", "The Bavarian State Centre for Civic Education (BLZ) informs citizens about political and social topics through publications, films and exhibitions."],
    7: [null, "München ist die Landeshauptstadt Bayerns und die drittgrößte Stadt Deutschlands. BMW, Allianz und MAN haben hier ihren Sitz; die Stadt ist bekannt für das Oktoberfest und die Isar.", "Munich is Bavaria's state capital and Germany's third-largest city. BMW, Allianz and MAN are headquartered here; the city is famous for Oktoberfest and the River Isar."],
    8: [null, "Bayern liegt im Südosten Deutschlands und grenzt an Österreich und Tschechien. Es ist mit über 70 000 km² das flächenmäßig größte Bundesland.", "Bavaria is in south-east Germany, bordering Austria and the Czech Republic. At over 70,000 km² it is Germany's largest state by area."],
    9: [null, "Der Regierungschef in Bayern heißt Ministerpräsident/in. Diese Bezeichnung gilt für alle 13 deutschen Flächenländer.", "The head of government in Bavaria is called Ministerpräsident/in. This title applies to all 13 German non-city states."],
    10: [null, "Bayern hat keinen Außenminister, weil Außenpolitik Bundesangelegenheit ist. Bayern unterhält jedoch eigene Vertretungen in Berlin und Brüssel, die Landesinteressen vertreten.", "Bavaria has no foreign minister because foreign policy is a federal matter. However, Bavaria maintains its own representations in Berlin and Brussels to represent state interests."]
  },
  "Berlin": {
    1: [null, "Das Wappen Berlins zeigt den roten Berliner Bären auf weißem Grund – eines der ältesten Wappentiere Deutschlands. Der Bär symbolisiert seit dem 13. Jahrhundert die Stadt.", "Berlin's coat of arms shows the red Berlin bear on a white background – one of Germany's oldest heraldic animals. The bear has symbolised the city since the 13th century."],
    2: [null, "Pankow ist der nördlichste Bezirk Berlins und der bevölkerungsreichste. Im Ortsteil Pankow befand sich nach 1949 der Regierungssitz der DDR-Führung.", "Pankow is Berlin's northernmost and most populous borough. In the Pankow district, the GDR leadership had its government seat after 1949."],
    3: [null, "Das Berliner Abgeordnetenhaus wird alle 5 Jahre gewählt. Als Stadtparlament hat es Funktionen eines Landtages und regelt die Gesetzgebung des Landes Berlin.", "Berlin's House of Representatives is elected every 5 years. As the city parliament it has the functions of a state parliament and governs Berlin's legislation."],
    4: [null, "In Berlin dürfen Jugendliche ab 16 Jahren bei der Wahl der Bezirksverordnetenversammlungen (BVV) abstimmen. Die BVV ist das Bezirksparlament – vergleichbar mit einem Stadtrat.", "In Berlin, young people aged 16 and over may vote in elections to the district assemblies (BVV). The BVV is the borough parliament – comparable to a city council."],
    5: [null, "Die Landesflagge Berlins ist weiß-rot. Auf der Flagge ist der rote Berliner Bär abgebildet. Die Farben Weiß und Rot gehen auf das historische Brandenburg zurück.", "Berlin's state flag is white and red. The flag shows the red Berlin bear. The colours white and red trace back to historical Brandenburg."],
    6: [null, "Die Berliner Landeszentrale für politische Bildung (LpB) informiert Bürgerinnen und Bürger über Politik und Demokratie. Sie bietet Veranstaltungen, Publikationen und Onlinematerialien an.", "The Berlin State Centre for Civic Education (LpB) informs citizens about politics and democracy. It offers events, publications and online materials."],
    7: [null, "Berlin ist einer der drei deutschen Stadtstaaten – ein Bundesland, das gleichzeitig eine Stadt ist. Die anderen Stadtstaaten sind Hamburg und Bremen.", "Berlin is one of Germany's three city-states – a federal state that is simultaneously a city. The other city-states are Hamburg and Bremen."],
    8: [null, "Berlin liegt im Nordosten Deutschlands, eingebettet im Bundesland Brandenburg. Die Stadt ist mit ca. 3,8 Millionen Einwohnern die bevölkerungsreichste Stadt Deutschlands.", "Berlin is in north-east Germany, surrounded by the state of Brandenburg. With about 3.8 million inhabitants it is Germany's most populous city."],
    9: [null, "In Berlin heißt der Regierungschef Regierender Bürgermeister/in. Dieser Titel ist typisch für Stadtstaaten, wo die Regierung ein Senat ist statt eines Kabinetts.", "In Berlin the head of government is called Governing Mayor (Regierender Bürgermeister/in). This title is typical for city-states, where the government is a Senate rather than a cabinet."],
    10: [null, "Berlin hat keine Senatorin/keinen Senator für Finanzen in dieser eigenständigen Form – das Finanzressort kann mit anderen Ressorts zusammengelegt sein. Außenpolitik ist grundsätzlich Bundesangelegenheit.", "Berlin has no standalone Senator for Finance in this form – the finance portfolio may be combined with others. Foreign policy is fundamentally a federal matter in Germany."]
  },
  "Brandenburg": {
    1: [null, "Das Wappen Brandenburgs zeigt den roten Adler auf weißem/silbernem Grund – ein Symbol seit dem Mittelalter. Der Adler war das Zeichen der Askanier, der Gründerdynastie der Mark Brandenburg.", "Brandenburg's coat of arms shows the red eagle on white/silver – a symbol since the Middle Ages. The eagle was the emblem of the Ascanians, the founding dynasty of the March of Brandenburg."],
    2: [null, "Die Prignitz ist ein Landkreis im Nordwesten Brandenburgs, bekannt für seine weite Natur, Elbtalaue und historische Städte wie Perleberg und Wittenberge.", "Prignitz is a district in north-west Brandenburg, known for its wide natural landscapes, the Elbe valley floodplains and historic towns like Perleberg and Wittenberge."],
    3: [null, "Der Brandenburger Landtag wird alle 5 Jahre gewählt. Brandenburg wurde 1990 als neues Bundesland gegründet und hat seitdem regelmäßig alle fünf Jahre gewählt.", "Brandenburg's state parliament is elected every 5 years. Brandenburg was founded as a new state in 1990 and has held elections every five years since then."],
    4: [null, "In Brandenburg dürfen Jugendliche ab 16 Jahren bei Kommunalwahlen abstimmen. Brandenburg war 2011 eines der frühen Bundesländer, das das kommunale Wahlalter auf 16 Jahre senkte.", "In Brandenburg, young people aged 16 and over may vote in local elections. Brandenburg was one of the early states to lower the local voting age to 16 in 2011."],
    5: [null, "Die Brandenburger Landesflagge ist rot-weiß. Rot und Weiß sind die historischen Farben der Mark Brandenburg und des Hohenzollernhauses.", "Brandenburg's state flag is red and white. Red and white are the historic colours of the March of Brandenburg and the House of Hohenzollern."],
    6: [null, "Die Brandenburgische Landeszentrale für politische Bildung informiert über politische Zusammenhänge in Deutschland und Brandenburg mit kostenfreien Publikationen und Veranstaltungen.", "The Brandenburg State Centre for Civic Education provides information on political contexts in Germany and Brandenburg through free publications and events."],
    7: [null, "Potsdam ist die Landeshauptstadt Brandenburgs und bekannt für die Schlösser und Gärten Sanssouci, die zum UNESCO-Weltkulturerbe gehören. Die Stadt liegt direkt an der Grenze zu Berlin.", "Potsdam is Brandenburg's state capital and famous for the Sanssouci palaces and gardens, a UNESCO World Heritage Site. The city borders directly on Berlin."],
    8: [null, "Brandenburg liegt im Nordosten Deutschlands und umschließt die Hauptstadt Berlin vollständig. Es grenzt an Polen und ist bekannt für seine Wälder, Seen und flachen Landschaften.", "Brandenburg is in north-east Germany and completely surrounds the capital Berlin. It borders Poland and is known for its forests, lakes and flat landscapes."],
    9: [null, "Der Regierungschef in Brandenburg heißt Ministerpräsident/in – wie in allen 13 deutschen Flächenländern.", "The head of government in Brandenburg is called Ministerpräsident/in – as in all 13 German non-city states."],
    10: [null, "Brandenburg hat keinen Außenminister. Außenpolitik ist ausschließlich Aufgabe des Bundes. Die Bundesländer können jedoch eigene Auslandsvertretungen haben, z. B. in Brüssel.", "Brandenburg has no foreign minister. Foreign policy is exclusively a federal responsibility. States can however maintain their own representations abroad, e.g. in Brussels."]
  },
  "Bremen": {
    1: [null, "Das Bremer Wappen zeigt einen silbernen (weißen) Schlüssel auf rotem Grund. Der Schlüssel ist das Zeichen des Heiligen Petrus, des Schutzpatrons des Bremer Doms.", "Bremen's coat of arms shows a silver (white) key on a red background. The key is the symbol of Saint Peter, the patron saint of Bremen Cathedral."],
    2: [null, "Hemelingen ist ein Stadtteil im Südosten Bremens mit großer Industriegeschichte. In Bremen gibt es keine Landkreise – als Stadtstaat ist es in Stadtteile statt Kreise unterteilt.", "Hemelingen is a district in south-east Bremen with a rich industrial history. Bremen has no rural districts (Landkreise) – as a city-state it is divided into neighbourhoods rather than counties."],
    3: [null, "Die Bremische Bürgerschaft wird alle 4 Jahre gewählt – kürzer als die meisten anderen Bundesländer, die 5-Jahres-Wahlperioden haben. Bremen ist damit das einzige Bundesland mit 4-jährigem Wahlzyklus.", "Bremen's parliament (Bürgerschaft) is elected every 4 years – shorter than most other states, which have 5-year terms. Bremen is the only state with a 4-year electoral cycle."],
    4: [null, "In Bremen dürfen Jugendliche ab 16 Jahren bei der Wahl zur Bürgerschaft (Landtag) wählen – das gilt auch für die Bremerhavener Stadtverordnetenversammlung. Bremen war bei der Absenkung des Wahlalters auf 16 ein Vorreiter.", "In Bremen, young people aged 16 and over may vote in elections to the Bürgerschaft (state parliament) – including for Bremerhaven's city assembly. Bremen was a pioneer in lowering the voting age to 16."],
    5: [null, "Die Landesflagge Bremens ist rot-weiß. Rot und Weiß sind die Stadtfarben, die seit dem Mittelalter mit Bremen verbunden werden. Das Stadtwappen mit dem weißen Schlüssel erscheint ebenfalls auf der Flagge.", "Bremen's state flag is red and white. Red and white are the city colours associated with Bremen since the Middle Ages. The city arms with the white key also appear on the flag."],
    6: [null, "Die Bremische Landeszentrale für politische Bildung bietet kostenlose Materialien und Informationen zu politischen Themen für Bürgerinnen und Bürger an.", "The Bremen State Centre for Civic Education offers free materials and information on political topics for citizens."],
    7: [null, "Bremen ist einer der drei deutschen Stadtstaaten und eine der ältesten Städte Deutschlands. Der Freistaat Bremen besteht aus zwei Städten: Bremen und Bremerhaven.", "Bremen is one of Germany's three city-states and one of its oldest cities. The Free Hanseatic City of Bremen consists of two cities: Bremen and Bremerhaven."],
    8: [null, "Bremen liegt im Nordwesten Deutschlands und ist vollständig vom Bundesland Niedersachsen umgeben. Als Hafenstadt an der Weser ist Bremen ein wichtiger Handelsstandort.", "Bremen is in north-west Germany and is completely surrounded by the state of Lower Saxony. As a port city on the Weser, Bremen is an important trading hub."],
    9: [null, "In Bremen heißt der Regierungschef Erster Bürgermeister/in (und gleichzeitig Präsident/in des Senats). Diese Bezeichnung ist typisch für den Stadtstaat Bremen.", "In Bremen the head of government is called First Mayor (Erster Bürgermeister/in) and simultaneously President of the Senate. This title is typical for the city-state of Bremen."],
    10: [null, "Bremen hat keinen Senator/keine Senatorin für Außenbeziehungen, da Außenpolitik ausschließlich Bundessache ist. Die Stadtstaaten haben Senatoren statt Minister.", "Bremen has no Senator for Foreign Affairs because foreign policy is exclusively a federal matter. City-states have Senators rather than Ministers."]
  },
  "Hamburg": {
    1: [null, "Das Wappen Hamburgs zeigt eine weiße Burg (Hammaburg) auf rotem Grund. Die Burg ist ein Symbol für die historische Befestigungsanlage, die im 9. Jahrhundert gegründet wurde.", "Hamburg's coat of arms shows a white castle (Hammaburg) on a red background. The castle symbolises the historic fortification founded in the 9th century."],
    2: [null, "Altona ist ein Bezirk im Westen Hamburgs und war bis 1937 eine eigenständige preußische Stadt. Heute ist es ein lebhaftes Stadtquartier direkt an der Elbe.", "Altona is a borough in western Hamburg and was an independent Prussian city until 1937. Today it is a lively urban quarter right on the River Elbe."],
    3: [null, "Die Hamburgische Bürgerschaft wird alle 5 Jahre gewählt. Als Stadtstaatparlament kombiniert sie die Aufgaben eines Landes- und Stadtparlaments.", "Hamburg's parliament (Bürgerschaft) is elected every 5 years. As a city-state parliament it combines the functions of both a state and city parliament."],
    4: [null, "In Hamburg dürfen Jugendliche ab 16 Jahren bei Wahlen zu den Bezirksversammlungen wählen. Hamburg hat das kommunale Wahlalter auf 16 Jahre gesenkt, um politische Teilhabe zu stärken.", "In Hamburg, young people aged 16 and over may vote in elections to the district assemblies. Hamburg lowered the local voting age to 16 to strengthen political participation."],
    5: [null, "Die Hamburger Landesflagge ist weiß-rot. Weiß und Rot sind die Hansefarben, die Hamburg seit dem Mittelalter trägt. Das weiße Schloss auf rotem Grund ziert auch das Wappen.", "Hamburg's state flag is white and red. White and red are the Hanseatic colours that Hamburg has carried since the Middle Ages. The white castle on red also adorns the coat of arms."],
    6: [null, "Die Hamburgische Landeszentrale für politische Bildung (LZ) informiert über politische und gesellschaftliche Themen mit Veranstaltungen, Publikationen und digitalen Angeboten.", "The Hamburg State Centre for Civic Education (LZ) informs citizens about political and social topics through events, publications and digital offerings."],
    7: [null, "Hamburg ist ein Stadtstaat – ein Bundesland, das gleichzeitig eine Stadt ist. Mit ca. 1,9 Millionen Einwohnern ist Hamburg die zweitgrößte Stadt Deutschlands und hat Europas drittgrößten Hafen.", "Hamburg is a city-state – a federal state that is simultaneously a city. With about 1.9 million inhabitants it is Germany's second-largest city and has Europe's third-largest port."],
    8: [null, "Hamburg liegt im Norden Deutschlands an der Elbe, etwa 100 km von der Nordseeküste entfernt. Es ist vollständig vom Bundesland Schleswig-Holstein und im Süden von Niedersachsen umgeben.", "Hamburg is in northern Germany on the River Elbe, about 100 km from the North Sea coast. It is surrounded entirely by Schleswig-Holstein and, to the south, Lower Saxony."],
    9: [null, "In Hamburg heißt der Regierungschef Erster Bürgermeister/in. Der Senat (Regierung) und die Bürgerschaft (Parlament) sind die zentralen Organe des Stadtstaates.", "In Hamburg the head of government is called First Mayor (Erster Bürgermeister/in). The Senate (government) and the Bürgerschaft (parliament) are the central organs of the city-state."],
    10: [null, "Hamburg hat keinen Senator/keine Senatorin für Außenbeziehungen, weil Außenpolitik Bundesangelegenheit ist. Hamburgs Senat hat Senatoren für Themen wie Inneres, Justiz, Finanzen und Soziales.", "Hamburg has no Senator for Foreign Affairs because foreign policy is a federal matter. Hamburg's Senate has Senators for topics such as interior, justice, finance and social affairs."]
  },
  "Hessen": {
    1: [null, "Das Wappen Hessens zeigt den silbernen (weißen) hessischen Löwen auf blauem Grund mit roter Krone und roten Streifen. Der Löwe ist ein Symbol der Landgrafen von Thüringen und Hessen.", "Hesse's coat of arms shows the silver Hessian lion on blue with a red crown and red stripes. The lion is a symbol of the Landgraves of Thuringia and Hesse."],
    2: [null, "Der Main-Taunus-Kreis liegt im Südwesten Hessens direkt vor den Toren Frankfurts. Er ist einer der wohlhabendsten Landkreise Deutschlands, geprägt durch Pendler und die Nähe zum Finanzplatz Frankfurt.", "The Main-Taunus district is in south-west Hesse, right on Frankfurt's doorstep. It is one of Germany's most affluent districts, shaped by commuters and proximity to Frankfurt's financial centre."],
    3: [null, "Der hessische Landtag wird alle 5 Jahre gewählt. Hessen hat eine der ältesten Verfassungen der Nachkriegszeit – die Hessische Verfassung von 1946.", "Hesse's state parliament is elected every 5 years. Hesse has one of the oldest post-war constitutions – the Hessian Constitution of 1946."],
    4: [null, "In Hessen liegt das Mindestalter für Kommunalwahlen bei 18 Jahren. Im Vergleich dazu haben viele andere Bundesländer das Wahlalter bereits auf 16 gesenkt.", "In Hesse the minimum voting age for local elections is 18. By comparison, many other states have already lowered the voting age to 16."],
    5: [null, "Die hessische Landesflagge ist rot-weiß. Die Farben stammen von den historischen Landgrafen von Hessen; Rot und Weiß waren schon im Mittelalter die hessischen Farben.", "Hesse's state flag is red and white. The colours come from the historical Landgraves of Hesse; red and white were already the Hessian colours in the Middle Ages."],
    6: [null, "Die Hessische Landeszentrale für politische Bildung (HLZ) in Wiesbaden bietet Bildungsangebote und kostenlose Publikationen zu politischen, historischen und gesellschaftlichen Themen.", "The Hessian State Centre for Civic Education (HLZ) in Wiesbaden offers educational programmes and free publications on political, historical and social topics."],
    7: [null, "Wiesbaden ist die Landeshauptstadt Hessens und bekannt als Kurstadt mit Thermalquellen. Obwohl Frankfurt die größte Stadt Hessens ist, ist Wiesbaden die Hauptstadt.", "Wiesbaden is Hesse's state capital and known as a spa city with thermal springs. Although Frankfurt is Hesse's largest city, Wiesbaden is the capital."],
    8: [null, "Hessen liegt im Herzen Deutschlands und grenzt an sechs Bundesländer. Frankfurt am Main ist das Finanzzentrum Deutschlands und Sitz der Europäischen Zentralbank (EZB).", "Hesse is in the heart of Germany, bordering six states. Frankfurt am Main is Germany's financial centre and home to the European Central Bank (ECB)."],
    9: [null, "Der Regierungschef in Hessen heißt Ministerpräsident/in – diese Bezeichnung gilt einheitlich für alle 13 deutschen Flächenländer.", "The head of government in Hesse is called Ministerpräsident/in – this title applies uniformly to all 13 German non-city states."],
    10: [null, "Hessen hat keinen Außenminister. Außenpolitik ist grundgesetzlich dem Bund vorbehalten. Deutschland wird international ausschließlich durch den Bundesaußenminister vertreten.", "Hesse has no foreign minister. Foreign policy is reserved for the federal government under the Basic Law. Germany is represented internationally solely by the Federal Foreign Minister."]
  },
  "Mecklenburg-Vorpommern": {
    1: [null, "Das Wappen Mecklenburg-Vorpommerns vereint den schwarzen Stier (Mecklenburg) und den roten Greif (Vorpommern) auf blau-weißem Feld. Der Greif ist ein mythisches Tier – halb Adler, halb Löwe.", "Mecklenburg-Vorpommern's coat of arms combines the black bull (Mecklenburg) and the red griffin (Vorpommern) on a blue-white field. The griffin is a mythical creature – half eagle, half lion."],
    2: [null, "Die Mecklenburgische Seenplatte ist der flächenmäßig größte Landkreis Deutschlands. Sie ist bekannt für über 1 000 Seen und ist ein beliebtes Natur- und Erholungsgebiet.", "The Mecklenburg Lake District is Germany's largest rural district by area. It is known for over 1,000 lakes and is a popular nature and recreation area."],
    3: [null, "Der Landtag in Mecklenburg-Vorpommern wird alle 5 Jahre gewählt. Das Bundesland wurde 1990 nach der Deutschen Wiedervereinigung neu gegründet.", "The state parliament in Mecklenburg-Vorpommern is elected every 5 years. The state was re-established in 1990 after German reunification."],
    4: [null, "In Mecklenburg-Vorpommern dürfen Jugendliche ab 16 Jahren bei Kommunalwahlen wählen. Das stärkt die politische Teilhabe junger Menschen in einem dünn besiedelten Bundesland.", "In Mecklenburg-Vorpommern, young people aged 16 and over may vote in local elections. This strengthens political participation of young people in a sparsely populated state."],
    5: [null, "Die Landesflagge MV ist blau-weiß-gelb-rot. Die vier Farben repräsentieren die historischen Herzogtümer und Gebiete: Blau-Weiß für Schwerin und Stargard, Gelb-Rot für Rostock und Vorpommern.", "MV's state flag is blue-white-yellow-red. The four colours represent the historical duchies and territories: blue-white for Schwerin and Stargard, yellow-red for Rostock and Pomerania."],
    6: [null, "Die Landeszentrale für politische Bildung Mecklenburg-Vorpommern (LpB) fördert demokratisches Bewusstsein durch kostenlose Angebote für Schulen, Vereine und die allgemeine Öffentlichkeit.", "The State Centre for Civic Education of Mecklenburg-Vorpommern (LpB) promotes democratic awareness through free resources for schools, associations and the general public."],
    7: [null, "Schwerin ist die Landeshauptstadt von Mecklenburg-Vorpommern und bekannt für das märchenhafte Schweriner Schloss auf einer Seeinsel. Es ist eine der kleinsten Landeshauptstädte Deutschlands.", "Schwerin is the state capital of Mecklenburg-Vorpommern and known for the fairytale Schwerin Palace on a lake island. It is one of Germany's smallest state capitals."],
    8: [null, "Mecklenburg-Vorpommern liegt im Nordosten Deutschlands an der Ostsee und grenzt an Polen. Es hat die längste Küstenlinie aller deutschen Bundesländer und ist sehr dünn besiedelt.", "Mecklenburg-Vorpommern is in north-east Germany on the Baltic Sea, bordering Poland. It has the longest coastline of all German states and is very sparsely populated."],
    9: [null, "Der Regierungschef in Mecklenburg-Vorpommern heißt Ministerpräsident/in – wie in allen Flächenländern.", "The head of government in Mecklenburg-Vorpommern is called Ministerpräsident/in – as in all non-city states."],
    10: [null, "Mecklenburg-Vorpommern hat keinen Außenminister, da Außenpolitik eine ausschließliche Bundesaufgabe ist. Kein deutsches Bundesland darf eigenständige Außenpolitik betreiben.", "Mecklenburg-Vorpommern has no foreign minister, as foreign policy is an exclusive federal responsibility. No German state may conduct independent foreign policy."]
  },
  "Niedersachsen": {
    1: [null, "Das Wappen Niedersachsens zeigt das Niedersächsische Ross – ein weißes, galoppierendes Pferd auf rotem Grund. Das Pferd ist seit dem Mittelalter das Symbol der Region.", "Lower Saxony's coat of arms shows the Lower Saxon horse – a white, galloping horse on a red background. The horse has been the symbol of the region since the Middle Ages."],
    2: [null, "Das Ammerland ist ein Landkreis in Nordwest-Niedersachsen, bekannt für seinen Baumschulanbau – eine der größten Baumschulregionen Europas. Die Gegend ist auch für ihre Rhododendronblüte bekannt.", "Ammerland is a district in north-west Lower Saxony, known for its nursery cultivation – one of Europe's largest nursery regions. The area is also famous for its rhododendron blossom."],
    3: [null, "Der niedersächsische Landtag wird alle 5 Jahre gewählt. Mit über 8 Millionen Einwohnern ist Niedersachsen nach NRW und Bayern das drittgrößte Bundesland Deutschlands.", "Lower Saxony's state parliament is elected every 5 years. With over 8 million inhabitants, Lower Saxony is Germany's third-largest state after NRW and Bavaria."],
    4: [null, "In Niedersachsen dürfen Jugendliche ab 16 Jahren bei Kommunalwahlen wählen. Das Wahlrecht ab 16 wurde eingeführt, um Jugendliche frühzeitig in demokratische Prozesse einzubinden.", "In Lower Saxony, young people aged 16 and over may vote in local elections. The right to vote at 16 was introduced to involve young people in democratic processes at an early stage."],
    5: [null, "Die Landesflagge Niedersachsens ist schwarz-gelb (schwarz-gold). Die Farben stammen vom Herzogtum Braunschweig und gehen auf das Welfenhaus zurück, das die Region jahrhundertelang regierte.", "Lower Saxony's state flag is black-yellow (black-gold). The colours come from the Duchy of Brunswick and trace back to the House of Welf, which ruled the region for centuries."],
    6: [null, "Die Niedersächsische Landeszentrale für politische Bildung (NLpB) bietet kostenlose Informationen und Bildungsangebote zu politischen Themen für Bürger, Schulen und Vereine.", "The Lower Saxony State Centre for Civic Education (NLpB) offers free information and educational programmes on political topics for citizens, schools and associations."],
    7: [null, "Hannover ist die Landeshauptstadt Niedersachsens und ein wichtiger Messe- und Industriestandort. Die Deutsche Messe AG veranstaltet hier u. a. die Hannover Messe, eine der weltgrößten Industriemessen.", "Hanover is Lower Saxony's state capital and a major trade fair and industrial location. Deutsche Messe AG hosts events here including Hannover Messe, one of the world's largest industrial trade fairs."],
    8: [null, "Niedersachsen liegt im Nordwesten Deutschlands und grenzt an die Niederlande. Es ist das zweitgrößte Bundesland nach Bayern und umfasst Landschaften vom Wattenmeer bis zum Harz.", "Lower Saxony is in north-west Germany, bordering the Netherlands. It is Germany's second-largest state after Bavaria, encompassing landscapes from the Wadden Sea to the Harz mountains."],
    9: [null, "Der Regierungschef in Niedersachsen heißt Ministerpräsident/in – einheitliche Bezeichnung für alle Flächenländer.", "The head of government in Lower Saxony is called Ministerpräsident/in – a uniform title for all non-city states."],
    10: [null, "Niedersachsen hat keinen Außenminister. Außenpolitik ist nach dem Grundgesetz ausschließlich Aufgabe des Bundes – kein Bundesland kann eigenständige Außenpolitik betreiben.", "Lower Saxony has no foreign minister. Under the Basic Law, foreign policy is exclusively a federal responsibility – no state can conduct independent foreign policy."]
  },
  "Nordrhein-Westfalen": {
    1: [null, "Das Wappen NRWs zeigt das Rheinische Kreuz, den westfälischen Adler und die lippische Rose. Diese drei Symbole stehen für die historischen Regionen Rheinland, Westfalen und Lippe.", "NRW's coat of arms shows the Rhinish cross, the Westphalian eagle and the Lippe rose. These three symbols represent the historic regions of Rhineland, Westphalia and Lippe."],
    2: [null, "Der Rhein-Sieg-Kreis liegt im Süden NRWs rund um die frühere Bundeshauptstadt Bonn. Er ist einer der bevölkerungsreichsten Landkreise Deutschlands.", "The Rhein-Sieg district is in southern NRW around the former federal capital Bonn. It is one of Germany's most populous rural districts."],
    3: [null, "Der NRW-Landtag wird alle 5 Jahre gewählt. NRW ist mit ca. 18 Millionen Einwohnern das bevölkerungsreichste Bundesland und hat daher großen Einfluss im Bundesrat.", "NRW's state parliament is elected every 5 years. With about 18 million inhabitants, NRW is Germany's most populous state and thus has significant influence in the Bundesrat."],
    4: [null, "In NRW dürfen Jugendliche ab 16 Jahren bei Kommunalwahlen wählen. Mehr politische Teilhabe für Jugendliche stärkt die demokratische Kultur in Deutschlands bevölkerungsreichstem Bundesland.", "In NRW, young people aged 16 and over may vote in local elections. Greater political participation for young people strengthens democratic culture in Germany's most populous state."],
    5: [null, "Die Landesflagge NRWs ist grün-weiß-rot. Grün steht für Westfalen und Lippe, Weiß für die Rheinlande und Rot für das Rheinische Wappenschild.", "NRW's state flag is green-white-red. Green represents Westphalia and Lippe, white represents the Rhineland and red represents the Rhinish heraldic shield."],
    6: [null, "Die Landeszentrale für politische Bildung NRW (LpB) hat ihren Sitz in Düsseldorf und unterstützt politische Bildung durch Publikationen, Seminare und Onlineangebote.", "The NRW State Centre for Civic Education (LpB) is based in Düsseldorf and supports civic education through publications, seminars and online resources."],
    7: [null, "Düsseldorf ist die Landeshauptstadt NRWs, bekannt für Mode, Wirtschaft und Kunst. Obwohl Köln und Dortmund größer sind, ist Düsseldorf die politische Hauptstadt des Landes.", "Düsseldorf is NRW's state capital, known for fashion, business and art. Although Cologne and Dortmund are larger, Düsseldorf is the state's political capital."],
    8: [null, "NRW liegt im Westen Deutschlands und grenzt an die Niederlande und Belgien. Es ist das industrielle Herzland Deutschlands – das Ruhrgebiet war lange das größte Industrierevier Europas.", "NRW is in western Germany, bordering the Netherlands and Belgium. It is Germany's industrial heartland – the Ruhr area was long Europe's largest industrial region."],
    9: [null, "Der Regierungschef in NRW heißt Ministerpräsident/in – wie in allen 13 deutschen Flächenländern.", "The head of government in NRW is called Ministerpräsident/in – as in all 13 German non-city states."],
    10: [null, "NRW hat keinen Außenminister. Außenpolitik ist nach dem Grundgesetz alleinige Aufgabe des Bundes. Die Bundesländer können jedoch EU-Interessen über den Bundesrat vertreten.", "NRW has no foreign minister. Foreign policy under the Basic Law is solely a federal responsibility. States can however represent EU interests through the Bundesrat."]
  },
  "Rheinland-Pfalz": {
    1: [null, "Das Wappen Rheinland-Pfalz' zeigt den Mainzer Reichsadler, den Trierer Kreuz-Löwen und den Pfälzer Löwen. Es vereint die drei historischen Regionen des 1946 neu gegründeten Bundeslandes.", "Rhineland-Palatinate's coat of arms shows the Mainz imperial eagle, the Trier cross-lion and the Palatine lion. It unites the three historic regions of the state founded in 1946."],
    2: [null, "Der Westerwaldkreis liegt im nördlichen Rheinland-Pfalz auf dem Westerwald-Plateau. Die Region ist bekannt für ihre Basaltgewinnung und traditionelle Töpferei (Kannenbäckerland).", "The Westerwald district is in northern Rhineland-Palatinate on the Westerwald plateau. The region is known for basalt quarrying and traditional pottery (Kannenbäckerland)."],
    3: [null, "Der rheinland-pfälzische Landtag wird alle 5 Jahre gewählt. RLP wurde 1946 von den französischen Besatzern gegründet und war ein Pionier beim Aufbau der deutschen Demokratie nach 1945.", "Rhineland-Palatinate's state parliament is elected every 5 years. RLP was founded by the French occupiers in 1946 and was a pioneer in building German democracy after 1945."],
    4: [null, "In Rheinland-Pfalz dürfen Jugendliche ab 16 Jahren bei Kommunalwahlen wählen. RLP senkte das kommunale Wahlalter 1994 als eines der ersten Bundesländer auf 16 Jahre.", "In Rhineland-Palatinate, young people aged 16 and over may vote in local elections. RLP was one of the first states to lower the local voting age to 16 in 1994."],
    5: [null, "Die Landesflagge RLP ist schwarz-rot-gold – die deutschen Nationalfarben. Als Zeichen der Demokratie und Einheit wurden diese Farben für das neue Nachkriegsbundesland gewählt.", "Rhineland-Palatinate's state flag is black-red-gold – the German national colours. As a symbol of democracy and unity, these colours were chosen for the new post-war state."],
    6: [null, "Die Landeszentrale für politische Bildung Rheinland-Pfalz (LpB) in Mainz informiert Bürgerinnen und Bürger über politische Themen und fördert demokratisches Engagement.", "The Rhineland-Palatinate State Centre for Civic Education (LpB) in Mainz informs citizens about political topics and promotes democratic engagement."],
    7: [null, "Mainz ist die Landeshauptstadt von Rheinland-Pfalz und Geburtsort von Johannes Gutenberg, dem Erfinder des Buchdrucks mit beweglichen Lettern (um 1450). Die Stadt liegt am Rhein, gegenüber von Wiesbaden.", "Mainz is Rhineland-Palatinate's state capital and birthplace of Johannes Gutenberg, inventor of printing with movable type (c. 1450). The city sits on the Rhine, opposite Wiesbaden."],
    8: [null, "Rheinland-Pfalz liegt im Westen Deutschlands und grenzt an Frankreich, Luxemburg und Belgien. Das Bundesland ist bekannt für seine Weinregionen – u. a. Mosel, Rhein, Pfalz.", "Rhineland-Palatinate is in western Germany, bordering France, Luxembourg and Belgium. The state is known for its wine regions – including Moselle, Rhine and Palatinate."],
    9: [null, "Der Regierungschef in Rheinland-Pfalz heißt Ministerpräsident/in – diese Bezeichnung gilt einheitlich für alle deutschen Flächenländer.", "The head of government in Rhineland-Palatinate is called Ministerpräsident/in – this title applies uniformly to all German non-city states."],
    10: [null, "Rheinland-Pfalz hat keinen Außenminister. Außenpolitik ist nach dem Grundgesetz ausschließlich Bundessache. Kein deutsches Bundesland hat das Recht, eigene Außenpolitik zu betreiben.", "Rhineland-Palatinate has no foreign minister. Foreign policy under the Basic Law is exclusively a federal matter. No German state has the right to conduct its own foreign policy."]
  },
  "Saarland": {
    1: [null, "Das Wappen des Saarlandes zeigt einen goldenen Löwen und eine Sonne – Symbole der historischen Grafschaft Saarbrücken und des lothringischen Adels. Es ist eines der farbenfröhlichsten deutschen Wappen.", "Saarland's coat of arms shows a golden lion and a sun – symbols of the historical County of Saarbrücken and Lotharingian nobility. It is one of Germany's most colourful coats of arms."],
    2: [null, "Neunkirchen ist ein Landkreis und eine der größten Städte des Saarlandes. Die Region war traditionell geprägt von Stahlproduktion und Bergbau; heute befindet sie sich im wirtschaftlichen Wandel.", "Neunkirchen is a district and one of Saarland's largest cities. The region was traditionally shaped by steel production and mining; today it is undergoing economic transformation."],
    3: [null, "Der saarländische Landtag wird alle 5 Jahre gewählt. Das Saarland ist das kleinste deutsche Flächenland und hat nur 51 Abgeordnete im Landtag.", "Saarland's state parliament is elected every 5 years. Saarland is Germany's smallest non-city state and has only 51 members in its parliament."],
    4: [null, "Im Saarland liegt das Mindestalter für Kommunalwahlen bei 18 Jahren. Das Saarland und Sachsen gehören zu den Bundesländern, die das kommunale Wahlalter noch nicht auf 16 gesenkt haben.", "In Saarland the minimum voting age for local elections is 18. Saarland and Saxony are among the states that have not yet lowered the local voting age to 16."],
    5: [null, "Die Landesflagge des Saarlandes ist schwarz-rot-gold – die deutschen Nationalfarben. Das Saarland wählte diese Farben als Bekenntnis zu Deutschland, nachdem es 1957 nach einer Volksabstimmung der Bundesrepublik beitrat.", "Saarland's state flag is black-red-gold – the German national colours. Saarland chose these colours as a commitment to Germany after joining the Federal Republic in 1957 following a referendum."],
    6: [null, "Die Landeszentrale für politische Bildung des Saarlandes (LpB) bietet Bürgerinnen und Bürgern kostenlose Materialien und Veranstaltungen zu politischen und demokratischen Themen.", "The Saarland State Centre for Civic Education (LpB) offers citizens free materials and events on political and democratic topics."],
    7: [null, "Saarbrücken ist die Landeshauptstadt des Saarlandes und die einzige Großstadt des Bundeslandes. Die Stadt liegt direkt an der Grenze zu Frankreich und ist ein Zentrum der deutsch-französischen Zusammenarbeit.", "Saarbrücken is Saarland's state capital and the state's only major city. The city sits directly on the border with France and is a centre of German-French cooperation."],
    8: [null, "Das Saarland liegt im Südwesten Deutschlands und grenzt an Frankreich und Luxemburg. Es ist das kleinste Flächenland Deutschlands und hat eine enge historische und kulturelle Verbindung zu Frankreich.", "Saarland is in south-west Germany, bordering France and Luxembourg. It is Germany's smallest non-city state and has close historical and cultural ties with France."],
    9: [null, "Der Regierungschef im Saarland heißt Ministerpräsident/in – einheitlich für alle Flächenländer.", "The head of government in Saarland is called Ministerpräsident/in – uniform for all non-city states."],
    10: [null, "Das Saarland hat keinen Außenminister. Außenpolitik ist nach dem Grundgesetz alleinige Aufgabe des Bundes. Das gilt für alle 16 deutschen Bundesländer.", "Saarland has no foreign minister. Foreign policy under the Basic Law is solely a federal responsibility. This applies to all 16 German states."]
  },
  "Sachsen": {
    1: [null, "Das Wappen Sachsens zeigt den grünen Rautenkranz auf golden-schwarzen Streifen. Der Rautenkranz (aus Rautenblättern) ist ein einzigartiges Symbol, das Sachsen seit dem 12. Jahrhundert unterscheidet.", "Saxony's coat of arms shows the green rue wreath on golden-black stripes. The rue wreath (made of rue leaves) is a unique symbol distinguishing Saxony since the 12th century."],
    2: [null, "Der Vogtlandkreis liegt im Südwesten Sachsens im Grenzgebiet zu Bayern, Thüringen, Tschechien. Er ist bekannt für Musikinstrumentenbau (u. a. Geigen und Gitarren) und seine historischen Viadukte.", "The Vogtland district is in south-west Saxony on the border with Bavaria, Thuringia and Czech Republic. It is known for musical instrument manufacturing (including violins and guitars) and its historic viaducts."],
    3: [null, "Der sächsische Landtag wird alle 5 Jahre gewählt. Sachsen ist eines der größten ostdeutschen Bundesländer und spielt eine wichtige wirtschaftliche Rolle mit der 'Sachsen-Dreieck'-Region.", "Saxony's state parliament is elected every 5 years. Saxony is one of the largest east German states and plays an important economic role with the 'Saxony Triangle' region."],
    4: [null, "In Sachsen liegt das Mindestalter für Kommunalwahlen bei 18 Jahren. Sachsen gehört neben Bayern und Hessen zu den Bundesländern, die das Wahlalter für lokale Wahlen noch nicht auf 16 gesenkt haben.", "In Saxony the minimum voting age for local elections is 18. Saxony, alongside Bavaria and Hesse, is among the states that have not yet lowered the voting age for local elections to 16."],
    5: [null, "Die Landesflagge Sachsens ist weiß-grün. Diese Farben stammen vom Haus Wettin, der sächsischen Herrscherdynastie, und sind seit dem Mittelalter die sächsischen Landesfarben.", "Saxony's state flag is white and green. These colours come from the House of Wettin, Saxony's ruling dynasty, and have been the Saxon state colours since the Middle Ages."],
    6: [null, "Die Sächsische Landeszentrale für politische Bildung (SLpB) in Dresden fördert politisches Wissen und demokratisches Engagement durch Bildungsprogramme, Publikationen und Veranstaltungen.", "The Saxon State Centre for Civic Education (SLpB) in Dresden promotes political knowledge and democratic engagement through educational programmes, publications and events."],
    7: [null, "Dresden ist die Landeshauptstadt Sachsens und bekannt als 'Elbflorenz' wegen seiner barocken Architektur. Die Semperoper und die Frauenkirche sind weltberühmte Wahrzeichen.", "Dresden is Saxony's state capital and known as 'Florence on the Elbe' for its Baroque architecture. The Semper Opera and the Frauenkirche are world-famous landmarks."],
    8: [null, "Sachsen liegt im Osten Deutschlands und grenzt an Polen und Tschechien. Es ist das bevölkerungsreichste ostdeutsche Bundesland und hat bedeutende Städte wie Dresden, Leipzig und Chemnitz.", "Saxony is in eastern Germany, bordering Poland and the Czech Republic. It is the most populous east German state, with significant cities including Dresden, Leipzig and Chemnitz."],
    9: [null, "Der Regierungschef in Sachsen heißt Ministerpräsident/in – wie in allen deutschen Flächenländern.", "The head of government in Saxony is called Ministerpräsident/in – as in all German non-city states."],
    10: [null, "Sachsen hat keinen Außenminister. Außenpolitik ist nach dem Grundgesetz ausschließlich eine Bundesaufgabe. Die 16 Bundesländer sind im außenpolitischen Bereich nicht handlungsfähig.", "Saxony has no foreign minister. Foreign policy under the Basic Law is exclusively a federal responsibility. The 16 states have no authority to act in the field of foreign policy."]
  },
  "Sachsen-Anhalt": {
    1: [null, "Das Wappen Sachsen-Anhalts zeigt den schwarzen Anhaltiner Bär auf gold-schwarzem Streifen (Sachsen) und den preußischen Adler. Es vereint die historischen Territorien Sachsen und Anhalt.", "Saxony-Anhalt's coat of arms shows the black Anhalt bear on gold-black stripes (Saxony) and the Prussian eagle. It unites the historic territories of Saxony and Anhalt."],
    2: [null, "Der Landkreis Börde liegt westlich von Magdeburg und ist eine der fruchtbarsten Ackerbauregionen Deutschlands. Die Schwarzerde-Böden der Magdeburger Börde gehören zu den besten Ackerböden Europas.", "The Börde district lies west of Magdeburg and is one of Germany's most fertile arable regions. The black-earth soils of the Magdeburg Börde are among Europe's finest agricultural soils."],
    3: [null, "Der Landtag in Sachsen-Anhalt wird alle 5 Jahre gewählt. Das Bundesland wurde 1990 neu gegründet und umfasst Gebiete, die historisch zu Preußen und den Herzogtümern Anhalt gehörten.", "Saxony-Anhalt's state parliament is elected every 5 years. The state was re-established in 1990 and comprises territories historically belonging to Prussia and the Anhalt duchies."],
    4: [null, "In Sachsen-Anhalt dürfen Jugendliche ab 16 Jahren bei Kommunalwahlen wählen. Die frühe politische Teilhabe soll Jugendliche für lokale Demokratie begeistern.", "In Saxony-Anhalt, young people aged 16 and over may vote in local elections. Early political participation is intended to enthuse young people for local democracy."],
    5: [null, "Die Landesflagge Sachsen-Anhalts ist gelb-schwarz. Die Farben stammen von den Hohenzollern (schwarz-weiß) und dem Herzogtum Anhalt (Gelb und Schwarz), die beide prägend für die Region waren.", "Saxony-Anhalt's state flag is yellow and black. The colours come from the Hohenzollerns (black-white) and the Duchy of Anhalt (yellow and black), both formative for the region."],
    6: [null, "Die Landeszentrale für politische Bildung Sachsen-Anhalt (LpB) hat ihren Sitz in Magdeburg und bietet kostenlose Materialien und Bildungsprogramme zur politischen und historischen Bildung.", "The Saxony-Anhalt State Centre for Civic Education (LpB) is based in Magdeburg and offers free materials and educational programmes on political and historical topics."],
    7: [null, "Magdeburg ist die Landeshauptstadt von Sachsen-Anhalt, geprägt durch Industrie und Geschichte. Der Magdeburger Dom ist eine der ältesten gotischen Kirchen Deutschlands.", "Magdeburg is the state capital of Saxony-Anhalt, shaped by industry and history. Magdeburg Cathedral is one of Germany's oldest Gothic churches."],
    8: [null, "Sachsen-Anhalt liegt in der Mitte Deutschlands und grenzt an sechs Bundesländer. Wittenberg, Geburtsort der Reformation, und die Gartenreiche Dessau-Wörlitz (UNESCO) liegen hier.", "Saxony-Anhalt is in central Germany, bordering six states. Wittenberg, birthplace of the Reformation, and the Dessau-Wörlitz Garden Kingdom (UNESCO) are located here."],
    9: [null, "Der Regierungschef in Sachsen-Anhalt heißt Ministerpräsident/in – einheitliche Bezeichnung für alle 13 deutschen Flächenländer.", "The head of government in Saxony-Anhalt is called Ministerpräsident/in – the uniform title for all 13 German non-city states."],
    10: [null, "Sachsen-Anhalt hat keinen Außenminister. Außenpolitik ist im deutschen Grundgesetz klar dem Bund vorbehalten. Nur der Bundesaußenminister vertritt Deutschland auf internationaler Ebene.", "Saxony-Anhalt has no foreign minister. Foreign policy is clearly reserved for the federal government in Germany's Basic Law. Only the Federal Foreign Minister represents Germany at the international level."]
  },
  "Schleswig-Holstein": {
    1: [null, "Das Wappen Schleswig-Holsteins zeigt das blaue Norder-Wasser (Schleswig) und den roten Holstein-Löwen auf Gold. Die beiden Symbole spiegeln die zwei historischen Herzogtümer wider.", "Schleswig-Holstein's coat of arms shows the blue Nordic water (Schleswig) and the red Holstein lion on gold. The two symbols reflect the two historic duchies."],
    2: [null, "Nordfriesland ist ein Landkreis ganz im Norden Schleswig-Holsteins, bekannt für die Nordfriesischen Inseln (u. a. Sylt, Föhr, Amrum) und die friesische Minderheit. Das Wattenmeer hier ist UNESCO-Weltnaturerbe.", "Nordfriesland is a district in the far north of Schleswig-Holstein, known for the North Frisian Islands (including Sylt, Föhr, Amrum) and the Frisian minority. The Wadden Sea here is a UNESCO Natural World Heritage Site."],
    3: [null, "Der schleswig-holsteinische Landtag wird alle 5 Jahre gewählt. SH ist das nördlichste Bundesland Deutschlands und grenzt an Dänemark.", "Schleswig-Holstein's state parliament is elected every 5 years. SH is Germany's northernmost state, bordering Denmark."],
    4: [null, "In Schleswig-Holstein dürfen Jugendliche ab 16 Jahren bei Kommunalwahlen wählen. SH war 2003 das erste Bundesland überhaupt, das das Wahlalter für Kommunalwahlen auf 16 Jahre gesenkt hat.", "In Schleswig-Holstein, young people aged 16 and over may vote in local elections. SH was in 2003 the very first state to lower the voting age for local elections to 16."],
    5: [null, "Die Landesflagge Schleswig-Holsteins ist blau-weiß-rot. Blau und Weiß stehen für Schleswig, Rot und Weiß für Holstein – die beiden historischen Herzogtümer, die 1867 zu Preußen kamen.", "Schleswig-Holstein's state flag is blue-white-red. Blue and white represent Schleswig, red and white represent Holstein – the two historic duchies that became part of Prussia in 1867."],
    6: [null, "Die Landeszentrale für politische Bildung Schleswig-Holstein (LpB) in Kiel bietet Informationen, Publikationen und Veranstaltungen zu politischen und demokratischen Themen.", "The Schleswig-Holstein State Centre for Civic Education (LpB) in Kiel offers information, publications and events on political and democratic topics."],
    7: [null, "Kiel ist die Landeshauptstadt Schleswig-Holsteins und ein bedeutender Hafen- und Marinestandort. Die Kieler Woche ist eine der größten Segelveranstaltungen der Welt.", "Kiel is Schleswig-Holstein's state capital and a major port and naval site. Kieler Woche (Kiel Week) is one of the world's largest sailing events."],
    8: [null, "Schleswig-Holstein liegt ganz im Norden Deutschlands zwischen Nord- und Ostsee. Es grenzt an Dänemark und ist das einzige deutsche Bundesland, das an zwei Meere grenzt.", "Schleswig-Holstein is in Germany's far north, between the North Sea and the Baltic. It borders Denmark and is the only German state that borders two seas."],
    9: [null, "Der Regierungschef in Schleswig-Holstein heißt Ministerpräsident/in – wie in allen deutschen Flächenländern.", "The head of government in Schleswig-Holstein is called Ministerpräsident/in – as in all German non-city states."],
    10: [null, "Schleswig-Holstein hat keinen Außenminister. Außenpolitik ist grundgesetzlich alleinige Aufgabe des Bundes. Bundesländer können Außenpolitik des Bundes allenfalls über den Bundesrat beeinflussen.", "Schleswig-Holstein has no foreign minister. Foreign policy is solely a federal responsibility under the Basic Law. States can at most influence federal foreign policy through the Bundesrat."]
  },
  "Thüringen": {
    1: [null, "Das Wappen Thüringens zeigt den rot-weißen thüringischen Löwen auf silbernem Grund. Der Löwe geht auf die Landgrafen von Thüringen zurück und ist seit dem 12. Jahrhundert das Symbol des Landes.", "Thuringia's coat of arms shows the red-white Thuringian lion on silver. The lion traces back to the Landgraves of Thuringia and has been the symbol of the state since the 12th century."],
    2: [null, "Der Wartburgkreis liegt im Südwesten Thüringens und ist benannt nach der Wartburg bei Eisenach – dem Ort, wo Martin Luther 1521/22 die Bibel ins Deutsche übersetzte. Die Wartburg ist UNESCO-Weltkulturerbe.", "The Wartburg district is in south-west Thuringia, named after Wartburg Castle near Eisenach – where Martin Luther translated the Bible into German in 1521/22. The Wartburg is a UNESCO World Heritage Site."],
    3: [null, "Der thüringische Landtag wird alle 5 Jahre gewählt. Thüringen liegt im Herzen Deutschlands und wird oft als 'Grünes Herz Deutschlands' bezeichnet.", "Thuringia's state parliament is elected every 5 years. Thuringia is in the heart of Germany and is often called the 'Green Heart of Germany'."],
    4: [null, "In Thüringen dürfen Jugendliche ab 16 Jahren bei Kommunalwahlen wählen. Thüringen senkte das Wahlalter, um junge Menschen früher in die politische Mitverantwortung einzubinden.", "In Thuringia, young people aged 16 and over may vote in local elections. Thuringia lowered the voting age to involve young people in political co-responsibility earlier."],
    5: [null, "Die Landesflagge Thüringens ist weiß-rot. Diese Farben stammen von den Landgrafen von Thüringen und dem Haus Weimar-Eisenach und sind seit dem Mittelalter die Farben der Region.", "Thuringia's state flag is white and red. These colours come from the Landgraves of Thuringia and the House of Weimar-Eisenach and have been the colours of the region since the Middle Ages."],
    6: [null, "Die Thüringer Landeszentrale für politische Bildung (LpB) in Erfurt bietet kostenlose Bildungsangebote und Informationsmaterialien zu politischen und demokratischen Themen.", "The Thuringia State Centre for Civic Education (LpB) in Erfurt offers free educational resources and information materials on political and democratic topics."],
    7: [null, "Erfurt ist die Landeshauptstadt Thüringens und eine der ältesten Städte Deutschlands. Johann Wolfgang von Goethe und Friedrich Schiller lebten und wirkten im nahe gelegenen Weimar.", "Erfurt is Thuringia's state capital and one of Germany's oldest cities. Johann Wolfgang von Goethe and Friedrich Schiller lived and worked in nearby Weimar."],
    8: [null, "Thüringen liegt im Herzen Deutschlands und grenzt an sechs Bundesländer. Der Thüringer Wald ist ein beliebtes Mittelgebirge; Weimar und der Nationalpark Hainich (UNESCO) sind Highlights.", "Thuringia is in the heart of Germany, bordering six states. The Thuringian Forest is a popular upland area; Weimar and the Hainich National Park (UNESCO) are highlights."],
    9: [null, "Der Regierungschef in Thüringen heißt Ministerpräsident/in – die einheitliche Bezeichnung für alle deutschen Flächenländer.", "The head of government in Thuringia is called Ministerpräsident/in – the uniform title for all German non-city states."],
    10: [null, "Thüringen hat keinen Außenminister. Außenpolitik obliegt nach dem Grundgesetz ausschließlich dem Bund. Diese Kompetenzverteilung gilt für alle 16 deutschen Bundesländer.", "Thuringia has no foreign minister. Under the Basic Law, foreign policy is the exclusive responsibility of the federal government. This division of powers applies to all 16 German states."]
  }
};
